-- 347_buildout_m11.sql (GENERATED) — fill empty lessons for "GPS/GNSS Surveying"
-- Module c100000b-0000-0000-0000-00000000000b. Namespaced by tag 'buildout' / created_by 'buildout:m11' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c100000b-0000-0000-0000-00000000000b' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c100000b-0000-0000-0000-00000000000b' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c100000b-0000-0000-0000-00000000000b' AND created_by='buildout:m11';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['GNSS positioning is satellite trilateration: each satellite range defines a sphere, and the receiver position is the intersection of several spheres.','Because the inexpensive receiver clock is not perfectly synchronized to satellite time, the clock bias is a fourth unknown, so at least four satellites are needed.','A GNSS is built from a space segment (satellites), a control segment (ground monitoring/upload stations), and a user segment (receivers); GPS is one of several GNSS constellations.']::text[], learning_objectives=ARRAY['Explain how a GNSS receiver computes a three-dimensional position by trilateration from satellite ranges.','Describe the three segments of a satellite positioning system (space, control, user) and the role of the receiver clock as a fourth unknown.','Distinguish the terms GPS and GNSS and state why a minimum of four satellites is required for an autonomous position.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='dc0422fa-cbeb-434c-aee0-2e0e8914bcad';
DELETE FROM lesson_blocks WHERE lesson_id='dc0422fa-cbeb-434c-aee0-2e0e8914bcad';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The four global constellations are GPS (USA), GLONASS (Russia), Galileo (EU), and BeiDou (China); regional systems (QZSS, NavIC) augment them.','Multi-constellation receivers see far more satellites, improving DOP and giving reliable fixes under canopy and in urban canyons.','GNSS satellites orbit in Medium Earth Orbit (~20,000 km) in several inclined planes with roughly 12-hour periods, so the visible sky pattern repeats predictably.']::text[], learning_objectives=ARRAY['Identify the four major GNSS constellations (GPS, GLONASS, Galileo, BeiDou) and their operators.','Explain how tracking multiple constellations improves satellite availability, geometry, and reliability for surveying.','Describe basic orbital characteristics (number of planes, altitude, period) that affect satellite visibility.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='e702897d-97dc-46bb-b473-c364fb27a420';
DELETE FROM lesson_blocks WHERE lesson_id='e702897d-97dc-46bb-b473-c364fb27a420';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['GPS broadcasts on carrier frequencies L1 (1575.42 MHz), L2 (1227.60 MHz), and L5 (1176.45 MHz), each modulated with ranging codes and the navigation message.','Code-phase (pseudorange) measurements are robust but meter-level; carrier-phase measurements are millimeter-resolution but carry an unknown integer number of whole cycles (the ambiguity) that must be resolved.','Observing two frequencies lets the receiver model and remove most of the frequency-dependent ionospheric delay, the largest range error after differencing.']::text[], learning_objectives=ARRAY['Describe the GPS carrier frequencies (L1, L2, L5) and the codes (C/A and P(Y)) modulated onto them.','Contrast code-phase (pseudorange) and carrier-phase measurements and explain the carrier-phase integer ambiguity.','Explain why dual-frequency observations are used to remove the ionospheric delay.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='3e13d01b-282e-419d-8204-e75e67537775';
DELETE FROM lesson_blocks WHERE lesson_id='3e13d01b-282e-419d-8204-e75e67537775';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Static surveying determines high-accuracy baseline vectors between two or more receivers that observe the same satellites simultaneously, cancelling common errors by differencing.','Longer occupations and dual-frequency data resolve carrier-phase ambiguities reliably; fast-static shortens occupation for short baselines with strong geometry.','Independent baselines are observed in sessions and combined by a least-squares network adjustment to produce coordinates with statistical quality measures.']::text[], learning_objectives=ARRAY['Describe the static and fast-static observation methods and the relative (differential) principle behind them.','Explain how baseline vectors between simultaneously occupied stations are computed and combined into a network.','Select appropriate occupation times based on baseline length, satellite geometry, and required accuracy.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='dfc1c937-bd48-4033-8cb1-004ac5872e5e';
DELETE FROM lesson_blocks WHERE lesson_id='dfc1c937-bd48-4033-8cb1-004ac5872e5e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['RTK uses a stationary base broadcasting corrections over a radio or cellular link so the moving rover computes a centimeter position in real time.','A valid RTK position requires a ''fixed'' solution (integer ambiguities resolved); a ''float'' solution is only decimeter-level and must not be used for survey points.','PPK collects the same observations but resolves baselines in the office afterward, trading real-time results for robustness when the data link is unreliable.']::text[], learning_objectives=ARRAY['Explain how RTK delivers centimeter positions in real time using a base station and a data link to the rover.','Distinguish RTK from PPK (post-processed kinematic) and describe initialization (ambiguity fixing) and ''fixed'' vs. ''float'' solutions.','Identify RTK''s practical limits: baseline length, data-link reliability, and the need for verification.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='28e3e9ec-70e5-43ba-bf60-0e554e32e613';
DELETE FROM lesson_blocks WHERE lesson_id='28e3e9ec-70e5-43ba-bf60-0e554e32e613';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A Real-Time Network (RTN) of permanent reference stations models errors across a region and streams corrections to a rover over the internet, so the user needs no base of their own.','Common methods include the Virtual Reference Station (VRS), Master-Auxiliary Concept (MAC), and FKP; all reduce the distance-dependent error that limits single-base RTK.','The NGS network of CORS supplies free archived data tied to the National Spatial Reference System for post-processing (e.g., OPUS) and underpins many RTNs.']::text[], learning_objectives=ARRAY['Explain how Network RTK (RTN) and Continuously Operating Reference Stations (CORS) provide corrections without a user-operated base.','Describe VRS, MAC, and FKP network correction approaches and the role of NGS CORS in the United States.','State the advantages and limitations of network corrections versus a single local base.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='e0b5a381-0a8a-4663-9c8b-0816e62c44f9';
DELETE FROM lesson_blocks WHERE lesson_id='e0b5a381-0a8a-4663-9c8b-0816e62c44f9';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['GNSS post-processing goes raw data → baseline vectors (with covariances) → least-squares network adjustment → adjusted coordinates with statistics.','Differencing (single/double/triple) cancels clocks and aids ambiguity fixing; precise ephemerides and PPP improve absolute accuracy.','A minimally constrained adjustment tests internal consistency; a fully constrained adjustment ties the network to published datum control.']::text[], learning_objectives=ARRAY['Describe the post-processing workflow from raw observations (RINEX) through baseline processing to a least-squares network adjustment.','Explain the role of differencing, precise ephemerides, and PPP in producing accurate coordinates.','Interpret adjustment quality measures (residuals, loop closures, error ellipses) and the difference between minimally and fully constrained adjustments.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='46586422-2833-4eb7-a4f0-f43afa0daae8';
DELETE FROM lesson_blocks WHERE lesson_id='46586422-2833-4eb7-a4f0-f43afa0daae8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['The main range errors are ionospheric delay (removable with dual frequency), tropospheric delay (modeled), multipath (sited away with good antennas), and satellite orbit/clock errors (reduced by differencing and precise products).','DOP is the geometry multiplier: poor (high) DOP from clustered satellites amplifies range error into large position error even when the ranges are good.','Estimated position error ≈ UERE × DOP, so good geometry and clean observations both matter.']::text[], learning_objectives=ARRAY['Identify the major GNSS error sources: ionospheric and tropospheric delay, multipath, orbit and clock errors, and receiver/antenna effects.','Explain Dilution of Precision (DOP) and how satellite geometry scales measurement error into position error.','Describe field and processing techniques that mitigate each error source.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='fbe7132a-2992-4500-b21e-33f4f5dc5d69';
DELETE FROM lesson_blocks WHERE lesson_id='fbe7132a-2992-4500-b21e-33f4f5dc5d69';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['GNSS yields ellipsoidal height h; orthometric (elevation) height H is obtained with a geoid model via H = h − N, where N is the geoid height.','NAD83 and WGS84/ITRF differ by ~1–2 m and are realized differently; mixing them blindly causes systematic errors, so know which datum your data are in.','GNSS provides strong control and long ties; total stations provide detail and work where the sky is blocked — integrate via shared control and a site localization.']::text[], learning_objectives=ARRAY['Reconcile GNSS heights with conventional (orthometric) elevations using the geoid model (H = h − N).','Explain datum considerations: NAD83 vs. WGS84/ITRF, and the coming NATRF2022 modernized datums.','Combine GNSS control with total-station traverses and localize/calibrate a site for construction.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='db07fb79-9728-47d7-8fc0-228e3e527bbf';
DELETE FROM lesson_blocks WHERE lesson_id='db07fb79-9728-47d7-8fc0-228e3e527bbf';
  'eeee1150-0000-0000-0000-000000000001', 'Orthometric height from GNSS ellipsoidal height and geoid height', 'Orthometric height from GNSS ellipsoidal height and geoid height', 'GPS/GNSS — Heights', 'Geoid model (H = h − N)', 'numeric_input', 'easy', 'A GNSS observation gives an ellipsoidal height of h = {{h:f2}} m at a point where the geoid model returns a geoid height of N = {{N:f2}} m. Using H = h − N, what is the orthometric (elevation) height H in meters?', 'h - N', '{"decimals":2,"unit":"m","tolerance":0.02}', '[{"name":"h","type":"float","min":80,"max":400,"decimals":2},{"name":"N","type":"float","min":-53,"max":-8,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Write the relationship","formula":"H = h − N","calculation_template":"H = {{h:f2}} − ({{N:f2}})"},{"step_number":2,"title":"Subtract the geoid height","result_template":"{{h:f2}} − ({{N:f2}}) = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Orthometric height H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} m. Because N is negative, subtracting it adds to the elevation — a common sign trap.', 'c100000b-0000-0000-0000-00000000000b', ARRAY['buildout','module-11','practice']::text[], true, 'buildout:m11');
  'eeee1150-0000-0000-0000-000000000002', 'Estimated position error from UERE and PDOP', 'Estimated position error from UERE and PDOP', 'GPS/GNSS — Error Analysis', 'DOP', 'numeric_input', 'medium', 'The combined per-satellite User Equivalent Range Error (UERE) for an observation is {{uere:f1}} m and the satellite geometry gives a PDOP of {{pdop:f1}}. Estimate the 3-D position error (m) using σ ≈ UERE × PDOP.', 'uere * pdop', '{"decimals":2,"unit":"m","tolerance":0.05}', '[{"name":"uere","type":"float","min":0.5,"max":4,"decimals":1},{"name":"pdop","type":"float","min":1.5,"max":6,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Write the relationship","formula":"σ ≈ UERE × PDOP","calculation_template":"σ ≈ {{uere:f1}} × {{pdop:f1}}"},{"step_number":2,"title":"Multiply","result_template":"{{uere:f1}} × {{pdop:f1}} = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Estimated position error ≈ UERE × PDOP = {{uere:f1}} × {{pdop:f1}} = {{_answer}} m. A high PDOP (weak geometry) inflates the position error even when the ranges themselves are good.', 'c100000b-0000-0000-0000-00000000000b', ARRAY['buildout','module-11','practice']::text[], true, 'buildout:m11');
  'eeee1150-0000-0000-0000-000000000003', 'Baseline error from the a + b·ppm model', 'Baseline error from the a + b·ppm model', 'GPS/GNSS — Static Surveying', 'Baseline accuracy model', 'numeric_input', 'medium', 'A GNSS baseline accuracy is specified as a constant term of {{a}} mm plus {{b}} ppm of the baseline length. For a baseline of {{D:f1}} km, what is the expected baseline error in MILLIMETERS? (1 ppm = 1 mm per km.)', 'a + b*D', '{"decimals":1,"unit":"mm","tolerance":0.1}', '[{"name":"a","type":"integer","min":3,"max":8},{"name":"b","type":"integer","min":1,"max":2},{"name":"D","type":"float","min":5,"max":40,"decimals":1}]'::jsonb, '[{"name":"ppmTerm","formula":"b*D"}]'::jsonb, '[{"step_number":1,"title":"Compute the ppm term","formula":"b ppm × D km = b·D mm","calculation_template":"{{b}} × {{D:f1}} = {{ppmTerm:f1}} mm"},{"step_number":2,"title":"Add the constant term","result_template":"{{a}} + {{ppmTerm:f1}} = {{_answer}} mm"}]'::jsonb, '{"method":"none"}'::jsonb, 'Baseline error = a + b·D = {{a}} mm + {{b}} ppm × {{D:f1}} km = {{a}} + {{ppmTerm:f1}} = {{_answer}} mm. The constant term dominates on short baselines; the ppm term grows with length.', 'c100000b-0000-0000-0000-00000000000b', ARRAY['buildout','module-11','practice']::text[], true, 'buildout:m11');
COMMIT;
SELECT 'm11 GPS/GNSS Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c100000b-0000-0000-0000-00000000000b') || ' blocks.' AS status;