INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000000', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'text', '{"html":"<h3>Positioning from Space</h3><p><strong>GNSS</strong> (Global Navigation Satellite System) is the general term for any constellation of navigation satellites that lets a receiver compute its position anywhere on or near the Earth, at any time, in any weather. <strong>GPS</strong> (the U.S. Global Positioning System) is the original and best-known GNSS, but it is only one of several &mdash; so a modern survey receiver is properly called a <em>GNSS receiver</em>, not just a &lsquo;GPS&rsquo;. The core idea is deceptively simple: each satellite continuously broadcasts its own position and a precise time signal, the receiver measures how long the signal took to arrive, multiplies by the speed of light to get a <strong>range</strong> (distance) to the satellite, and uses several such ranges to locate itself.</p><p>Geometrically this is <strong>trilateration</strong>. A single range places the receiver somewhere on a sphere centered on that satellite. Two ranges narrow the position to a circle, three to a pair of points, and a fourth resolves the ambiguity and &mdash; crucially &mdash; solves for the receiver clock error. The result is a three-dimensional coordinate (latitude, longitude, height, or X, Y, Z) referenced to a global datum.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000001', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'text', '{"html":"<h3>Why Four Satellites?</h3><p>To turn travel time into distance you must know <em>when</em> the signal left the satellite and <em>when</em> it arrived. Each satellite carries an atomic clock and is tightly synchronized to system time, but the receiver uses a cheap quartz clock that drifts. That receiver <strong>clock bias</strong> appears in every range measurement, so the raw distances are really <em>pseudoranges</em> &mdash; ranges contaminated by a common timing error. The position solution therefore has <strong>four unknowns</strong>: the three position coordinates (X, Y, Z) plus the receiver clock bias. Four equations require four satellites; tracking more than four over-determines the solution and improves accuracy and reliability.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000002', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'equation', '{"latex":"\\rho_i = \\sqrt{(X_i - X)^2 + (Y_i - Y)^2 + (Z_i - Z)^2} + c\\,\\delta t","label":"Pseudorange to satellite i: (X,Y,Z) receiver, (Xi,Yi,Zi) satellite, δt clock bias","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000003', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'text', '{"html":"<h3>The Three Segments of a GNSS</h3><p>Every GNSS is organized into three parts. The <strong>space segment</strong> is the constellation of satellites broadcasting timing and orbit (ephemeris) data. The <strong>control segment</strong> is a network of ground stations that track the satellites, compute precise orbits and clock corrections, and upload that data to the satellites &mdash; for GPS this is run by the U.S. Space Force, with a master control station and globally distributed monitor stations. The <strong>user segment</strong> is everyone with a receiver, from a phone to a survey-grade dual-frequency rover. Surveyors operate in the user segment but must understand the other two, because orbit and clock quality (from the control segment) and satellite geometry (from the space segment) directly limit the accuracy a receiver can achieve.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000004', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'table', '{"headers":["Segment","Contents","Function"],"rows":[["Space","The satellite constellation","Broadcasts timing signals and ephemeris (orbit) data"],["Control","Master + monitor/upload ground stations","Tracks satellites, computes orbit/clock corrections, uploads to satellites"],["User","Receivers (handheld to survey-grade)","Receives signals, computes position, velocity, time"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000005', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'callout', '{"type":"info","text":"Navigation-grade autonomous GPS gives roughly 3–10 m horizontal accuracy. Survey-grade results (centimeter to sub-centimeter) come not from a better single position but from relative/differential techniques and carrier-phase measurements covered later in this module."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000006', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: GNSS trilateration. Each measured range defines a sphere about its satellite; the receiver lies at the common intersection, with a fourth satellite resolving the receiver clock bias."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0001-0000-0000-000000000007', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'key_takeaways', '{"title":"Key Takeaways","items":["GNSS is satellite trilateration: range to each satellite defines a sphere; the receiver is at the common intersection.","Raw distances are pseudoranges because the receiver clock is biased; the clock error is a fourth unknown.","At least four satellites are needed for an autonomous 3-D position; more satellites improve accuracy and reliability.","A GNSS has space, control, and user segments; GPS is one GNSS among several.","Autonomous accuracy is a few meters; centimeter survey accuracy requires the relative and carrier-phase methods covered later."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000000', 'e702897d-97dc-46bb-b473-c364fb27a420', 'text', '{"html":"<h3>A Crowded Sky</h3><p>For its first decades, satellite surveying meant GPS alone, often supplemented by the Russian <strong>GLONASS</strong>. Today four fully global constellations operate, and modern survey receivers track all of them simultaneously. The U.S. <strong>GPS</strong>, Russia''s <strong>GLONASS</strong>, the European Union''s <strong>Galileo</strong>, and China''s <strong>BeiDou</strong> together place well over a hundred usable satellites in the sky, plus regional augmentation systems such as Japan''s <strong>QZSS</strong> and India''s <strong>NavIC</strong>. Each system is independently operated, with its own satellites, ground control, and signal plan, but their signals are interoperable enough that a single receiver can blend them into one position solution.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000001', 'e702897d-97dc-46bb-b473-c364fb27a420', 'table', '{"headers":["Constellation","Operator","Orbit altitude","Nominal satellites"],"rows":[["GPS","United States (Space Force)","~20,200 km MEO","31 operational"],["GLONASS","Russia","~19,100 km MEO","24"],["Galileo","European Union","~23,200 km MEO","24+ "],["BeiDou (BDS)","China","MEO + IGSO/GEO mix","30+"],["QZSS / NavIC","Japan / India (regional)","IGSO/GEO","Regional augmentation"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000002', 'e702897d-97dc-46bb-b473-c364fb27a420', 'text', '{"html":"<h3>Why Multi-Constellation Matters</h3><p>For a surveyor the practical payoff of multiple constellations is <strong>more satellites in view, better geometry, and faster, more reliable fixes</strong>. Each constellation puts satellites in <strong>Medium Earth Orbit (MEO)</strong>, roughly 19,000&ndash;23,000 km up, in several inclined orbital planes with periods near 12 hours, so satellites are spread across the whole sky and the pattern repeats predictably each day. When you work under tree canopy, beside buildings, or in an urban canyon, half the sky may be blocked. Tracking GPS alone you might drop below the four satellites needed; tracking GPS + GLONASS + Galileo + BeiDou you may still see 15&ndash;25 satellites, keeping a strong solution where single-constellation work would fail. More satellites also improve <strong>DOP</strong> (dilution of precision &mdash; the geometry factor covered later) and let the receiver reject bad observations.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000003', 'e702897d-97dc-46bb-b473-c364fb27a420', 'callout', '{"type":"info","text":"GLONASS satellites historically used FDMA (each satellite on a slightly different frequency) while GPS, Galileo, and BeiDou use CDMA (shared frequencies, different codes). This is why some older or lower-cost receivers track GPS-only — handling GLONASS adds complexity. Survey-grade receivers handle all systems."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000004', 'e702897d-97dc-46bb-b473-c364fb27a420', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: GNSS satellites occupy several inclined orbital planes in Medium Earth Orbit, so satellites are distributed across the whole sky and the visibility pattern repeats daily."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0002-0000-0000-000000000005', 'e702897d-97dc-46bb-b473-c364fb27a420', 'key_takeaways', '{"title":"Key Takeaways","items":["Four global GNSS constellations: GPS (USA), GLONASS (Russia), Galileo (EU), BeiDou (China); QZSS and NavIC are regional augmentations.","GNSS satellites fly in MEO (~20,000 km) in several inclined planes with ~12-hour periods, repeating their sky pattern daily.","Multi-constellation tracking dramatically increases satellites in view, improving DOP and reliability under canopy and in urban canyons.","GLONASS uses FDMA; GPS, Galileo, and BeiDou use CDMA — a reason older receivers may be GPS-only.","Survey-grade receivers blend all constellations into a single, robust position solution."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000000', '3e13d01b-282e-419d-8204-e75e67537775', 'text', '{"html":"<h3>What the Satellite Broadcasts</h3><p>Each GPS satellite transmits microwave <strong>carrier waves</strong> at precise frequencies derived from its atomic clock. The legacy frequencies are <strong>L1 at 1575.42 MHz</strong> and <strong>L2 at 1227.60 MHz</strong>; modernized satellites add <strong>L5 at 1176.45 MHz</strong> (and new civil codes on L1 and L2). Onto these carriers the satellite <em>modulates</em> two things: ranging <strong>codes</strong> and the <strong>navigation message</strong>. The navigation message carries the satellite''s ephemeris (precise orbit), clock corrections, and almanac. The ranging codes are pseudo-random sequences the receiver matches against an internally generated copy to measure signal travel time.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000001', '3e13d01b-282e-419d-8204-e75e67537775', 'text', '{"html":"<h3>The Ranging Codes: C/A and P(Y)</h3><p>Two principal codes ride on the GPS carriers. The <strong>C/A code</strong> (Coarse/Acquisition) is on L1, repeats every millisecond, and is the basis of standard civilian positioning &mdash; easy to acquire but relatively coarse. The <strong>P code</strong> (Precise), encrypted into the <strong>P(Y) code</strong> for military use, is on both L1 and L2, runs at a much higher chipping rate, and gives finer code-phase ranging. The receiver determines the <strong>code phase</strong> by sliding its replica of the code until it correlates with the incoming signal; the time shift, times the speed of light, is the <strong>pseudorange</strong>. Code-phase positioning is robust and instantaneous but limited to roughly meter-level precision because the code chips are physically long.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000002', '3e13d01b-282e-419d-8204-e75e67537775', 'text', '{"html":"<h3>Carrier Phase: The Surveyor''s Tool</h3><p>For centimeter accuracy, surveyors measure the <strong>carrier phase</strong> rather than the code. The L1 carrier has a wavelength of only about <strong>19 cm</strong> (L2 about 24 cm), and the receiver can measure a fraction of one cycle to better than a millimeter. The catch is the <strong>integer ambiguity</strong>: the receiver can measure the fractional phase and count cycles <em>after</em> lock-on, but it does not initially know the whole number of complete wavelengths between satellite and antenna. Resolving that integer &mdash; &lsquo;fixing the ambiguities&rsquo; &mdash; is what turns a noisy float solution into a centimeter-level <strong>fixed</strong> solution, and is the central problem in static and RTK processing.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000003', '3e13d01b-282e-419d-8204-e75e67537775', 'equation', '{"latex":"\\Phi = \\frac{1}{\\lambda}\\,r + N + \\text{(clock, atmosphere terms)}","label":"Carrier-phase observable: r range, λ wavelength, N unknown integer ambiguity","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000004', '3e13d01b-282e-419d-8204-e75e67537775', 'text', '{"html":"<h3>Why Two Frequencies?</h3><p>The ionosphere delays the GNSS signal by an amount that depends on <strong>frequency</strong> &mdash; lower frequencies are delayed more. By observing the <em>same</em> satellite on two frequencies (L1 and L2, or L1/L5), the receiver can form a <strong>linear combination</strong> that cancels almost all of the first-order ionospheric delay, the single largest error source over long baselines. This is why survey-grade receivers are <strong>dual-frequency</strong> (now often triple-frequency): the extra frequency is not for redundancy alone but to eliminate the ionosphere and to help resolve the integer ambiguities faster. Single-frequency receivers must instead rely on a broadcast ionosphere model, which leaves larger residual error.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000005', '3e13d01b-282e-419d-8204-e75e67537775', 'table', '{"headers":["Frequency","Value","Approx. wavelength","Carries"],"rows":[["L1","1575.42 MHz","≈ 19 cm","C/A code, P(Y), new L1C, nav message"],["L2","1227.60 MHz","≈ 24 cm","P(Y), civil L2C"],["L5","1176.45 MHz","≈ 25 cm","Modernized civil safety-of-life signal"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000006', '3e13d01b-282e-419d-8204-e75e67537775', 'callout', '{"type":"info","text":"Rule of thumb: code-phase (pseudorange) gives meters and works instantly; carrier-phase gives millimeters but needs the integer ambiguities resolved. Surveying lives on carrier phase; the code is mainly used to get close enough to fix the ambiguities."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000007', '3e13d01b-282e-419d-8204-e75e67537775', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A GPS signal — the carrier wave (L1/L2/L5) modulated with the ranging code and navigation message. Carrier-phase measurement uses the ~19 cm wavelength for millimeter resolution."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0003-0000-0000-000000000008', '3e13d01b-282e-419d-8204-e75e67537775', 'key_takeaways', '{"title":"Key Takeaways","items":["GPS carriers are L1 (1575.42 MHz), L2 (1227.60 MHz), and L5 (1176.45 MHz), carrying ranging codes and the navigation message.","The C/A code (civil, L1) and encrypted P(Y) code (L1/L2) support code-phase pseudoranging at meter level.","Carrier-phase measurement reaches millimeter resolution but carries an unknown integer ambiguity that must be ''fixed.''","Dual-frequency observation forms a combination that removes most ionospheric delay and speeds ambiguity resolution.","Surveying relies on carrier phase; the code provides the approximate range used to resolve the integers."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000000', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'text', '{"html":"<h3>The Relative (Differential) Principle</h3><p>Static GPS surveying is the highest-accuracy GNSS method and the backbone of geodetic control. Its power comes from <strong>relative positioning</strong>: two (or more) receivers occupy stations and observe the <em>same satellites at the same time</em>. Because both receivers see nearly identical satellite clock, orbit, and atmospheric errors, <strong>differencing</strong> their observations cancels most of those errors. The product is not an absolute position of each station but a precise <strong>baseline vector</strong> &mdash; the three-dimensional &Delta;X, &Delta;Y, &Delta;Z between the two antennas &mdash; good to a few millimeters plus a small part-per-million term with baseline length.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000001', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'text', '{"html":"<h3>Static vs. Fast-Static</h3><p>In classic <strong>static</strong> work, receivers occupy each station for a relatively long session &mdash; from twenty minutes on short baselines to several hours on long or high-accuracy ones &mdash; logging carrier-phase data at a fixed epoch interval. The long occupation gives the processing software enough changing geometry and redundant observations to <strong>resolve the integer ambiguities</strong> with confidence, even over tens of kilometers. <strong>Fast-static</strong> (rapid-static) shortens the occupation to a few minutes by exploiting dual-frequency data and good satellite geometry; it suits dense control on short baselines but is less robust on long lines or under poor geometry. Both are <em>post-processed</em>: data is collected in the field and the baselines are computed later in the office.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000002', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'equation', '{"latex":"\\sigma_{\\text{baseline}} = a_{mm} + b_{ppm}\\cdot D_{km}","label":"Typical baseline accuracy: constant term plus a part-per-million term scaling with length D","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000003', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'text', '{"html":"<h3>From Baselines to a Network</h3><p>A control survey rarely measures a single baseline. Receivers are moved through a series of <strong>sessions</strong>, each producing several simultaneous baselines, until every station is tied by independent vectors forming a closed network with redundancy. Those baseline vectors, each with its own covariance (error estimate), are then combined in a <strong>least-squares network adjustment</strong>. The adjustment distributes small inconsistencies, holds known control fixed, and yields adjusted coordinates together with statistical measures &mdash; standard deviations and error ellipses &mdash; that document the achieved accuracy. Planning aims for enough redundant, independent baselines that blunders can be detected and the network checked, not just computed.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000004', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'table', '{"headers":["Method","Typical occupation","Best for","Processing"],"rows":[["Static","20 min – several hours","Long baselines, geodetic control, highest accuracy","Post-processed"],["Fast-static","A few minutes","Short baselines, dense control, strong geometry","Post-processed"],["RTK (next lesson)","Seconds","Real-time topo/stakeout","Real-time"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000005', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'callout', '{"type":"info","text":"Planning tip: occupation time scales with baseline length and required accuracy and inversely with satellite geometry. A short, well-observed baseline may fix in minutes; a 30 km geodetic baseline may need an hour or more of dual-frequency data for a reliable fixed solution."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000006', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A static GPS network — independent baseline vectors between simultaneously occupied stations form redundant closed loops, then combine in a least-squares adjustment."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0004-0000-0000-000000000007', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'key_takeaways', '{"title":"Key Takeaways","items":["Static surveying uses relative positioning: simultaneous observation lets differencing cancel common satellite, orbit, and atmosphere errors.","The product is a baseline vector (ΔX, ΔY, ΔZ) accurate to a few mm plus a small ppm term that grows with length.","Long static occupations reliably fix ambiguities over long baselines; fast-static is shorter but limited to short baselines with strong geometry.","Both static and fast-static are post-processed in the office, not real-time.","Independent baselines are observed in sessions and combined by a least-squares network adjustment with statistical quality measures."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000000', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'text', '{"html":"<h3>Centimeters in Real Time</h3><p><strong>Real-Time Kinematic (RTK)</strong> surveying takes the relative-positioning principle and delivers the answer <em>immediately</em> in the field. A receiver set over a known point &mdash; the <strong>base</strong> &mdash; continuously broadcasts its raw observations or corrections to a moving <strong>rover</strong> over a data link (UHF radio or cellular internet, usually in the RTCM format). The rover combines the base data with its own observations, fixes the carrier-phase ambiguities on the fly, and reports a centimeter-level position several times per second. This makes RTK the workhorse for topographic mapping, stakeout, boundary location, and construction layout where speed matters and baselines are short (typically within a few to ~20 km of the base).</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000001', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'text', '{"html":"<h3>Fixed vs. Float &mdash; Initialization</h3><p>RTK accuracy hinges on <strong>resolving the integer ambiguities</strong>, a step called <strong>initialization</strong>. While the rover is still solving for the integers it reports a <strong>float</strong> solution &mdash; only decimeter-level and <em>not</em> survey-grade. Once the integers are fixed, the rover reports a <strong>fixed</strong> solution good to roughly 1&ndash;2 cm horizontally and 2&ndash;4 cm vertically. <strong>A surveyor must store points only on a verified fixed solution.</strong> Modern receivers initialize in seconds, but loss of lock (passing under a tree, a bridge, or a building) drops the solution back to float, and the rover must re-fix before reliable points can be measured again.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000002', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'callout', '{"type":"warning","text":"Texas differs / professional standard: GNSS-located boundary and control points must meet the accuracy and procedural standards in the Texas Board of Professional Engineers and Land Surveyors General Rules of Procedures and Practices (22 TAC Ch. 663). Always verify the RTK fix by re-observing key points (independent occupation, different time/satellite geometry) and checking into known control — never trust a single float or unverified fixed reading."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000003', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'text', '{"html":"<h3>RTK vs. PPK</h3><p><strong>Post-Processed Kinematic (PPK)</strong> uses the same moving-rover, short-occupation idea but skips the real-time data link: base and rover each log raw data, and the baselines are computed in the office afterward. PPK trades the immediacy of RTK for <strong>robustness</strong> &mdash; there is no radio to fail, the software can process forward and backward in time to recover from cycle slips, and ambiguity fixing can be more rigorous. RTK is preferred when you need the coordinate on the spot (stakeout); PPK shines where a data link is impractical (remote areas, UAS-mounted receivers) or where maximum reliability is wanted. Many systems can do both: collect RTK in the field and reprocess as PPK as a check.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000004', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'table', '{"headers":["Aspect","RTK","PPK"],"rows":[["Results","Real-time, in the field","Computed later in office"],["Data link","Required (radio or cellular)","Not required"],["Typical accuracy","1–2 cm H, 2–4 cm V","Comparable, often more robust"],["Best for","Stakeout, on-the-spot location","Remote areas, UAS, max reliability"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000005', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: An RTK setup — a base over known control broadcasts corrections to the rover, which fixes the ambiguities and reports a centimeter position in real time."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0005-0000-0000-000000000006', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'key_takeaways', '{"title":"Key Takeaways","items":["RTK delivers centimeter positions in real time using a base, a data link, and a roving receiver.","Only a verified ''fixed'' (ambiguity-resolved) solution is survey-grade; a ''float'' solution is decimeter-level and must not be stored as a point.","Initialization fixes the integers; loss of lock drops to float and requires re-fixing.","PPK collects the same data but resolves baselines in the office, trading real-time results for robustness and no data-link dependence.","Always verify GNSS points by re-observation and checks into known control, per professional/Texas standards."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000000', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'text', '{"html":"<h3>Beyond a Single Base</h3><p>Single-base RTK has two practical weaknesses: someone must set up and guard a base over known control, and accuracy degrades as the rover moves farther from that base (the distance-dependent ionospheric, tropospheric, and orbit errors grow). <strong>Network RTK</strong> &mdash; also called a <strong>Real-Time Network (RTN)</strong> &mdash; solves both. A region is covered by a permanent grid of <strong>reference stations</strong> spaced tens of kilometers apart. A central server continuously models the atmospheric and orbit errors across the whole network and streams a tailored correction to each rover over a cellular internet link. The surveyor simply turns on one rover, logs into the network, and works at centimeter accuracy with <em>no base of their own</em>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000001', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'text', '{"html":"<h3>How Networks Deliver Corrections</h3><p>Several standard schemes exist. In the <strong>Virtual Reference Station (VRS)</strong> approach the server uses the rover''s approximate position to synthesize the observations a nearby imaginary base would record, so the rover behaves as if it had a base just meters away. The <strong>Master-Auxiliary Concept (MAC / MAX)</strong> sends data from a master station plus correction differences from auxiliary stations, letting the rover do more of the interpolation. <strong>FKP</strong> (Fl&auml;chenkorrekturparameter, area correction parameters) broadcasts coefficients describing how the corrections vary with position. All three aim at the same goal: remove the <strong>distance-dependent error</strong> so accuracy stays uniform across the coverage area rather than degrading with distance from a single base.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000002', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'table', '{"headers":["Method","How it works","Key trait"],"rows":[["VRS","Server synthesizes a virtual base near the rover","Rover acts as if base is a few meters away"],["MAC / MAX","Master station + auxiliary correction differences","Rover interpolates; standards-based, broadcastable"],["FKP","Area correction parameters streamed to rover","Coefficients model spatial variation of error"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000003', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'text', '{"html":"<h3>CORS and the National Spatial Reference System</h3><p>In the United States the National Geodetic Survey (NGS) coordinates a network of <strong>Continuously Operating Reference Stations (CORS)</strong> &mdash; permanent GNSS stations whose data are freely archived and whose coordinates are tied to the <strong>National Spatial Reference System (NSRS)</strong>. CORS underpin both real-time networks and post-processing. A surveyor can submit a static data file to the free NGS <strong>OPUS</strong> (Online Positioning User Service), which processes it against nearby CORS and returns NSRS coordinates &mdash; an easy way to establish a control point or check a base. Many state and commercial RTNs are built on or referenced to CORS, which is why network results are inherently tied to the official datum.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000004', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'callout', '{"type":"info","text":"Texas note: the Texas Department of Transportation and several commercial providers operate RTNs covering most of the state, and numerous NGS CORS sit within Texas. Network RTK is widely used for routine work, but for boundary/control you still verify against published NSRS control and follow the Board''s positional-accuracy requirements."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000005', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A Real-Time Network. Permanent reference stations feed a server that models regional errors and streams a tailored correction (e.g., a VRS) to each rover — no user base required."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0006-0000-0000-000000000006', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'key_takeaways', '{"title":"Key Takeaways","items":["Network RTK (RTN) uses a regional grid of permanent reference stations and a server to stream corrections over the internet, removing the need for a user base.","VRS, MAC/MAX, and FKP are the main network methods; all reduce the distance-dependent error that limits single-base RTK.","Accuracy stays uniform across the network rather than degrading with distance from one base.","NGS CORS provide free archived data tied to the NSRS, supporting OPUS post-processing and underpinning many RTNs.","Network results are tied to the official datum, but boundary/control work must still verify against published control and meet accuracy standards."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000000', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'text', '{"html":"<h3>From Raw Data to Coordinates</h3><p>Post-processed GNSS surveying produces its accuracy in the office. The workflow starts with <strong>raw observation files</strong>, usually exported in the receiver-independent <strong>RINEX</strong> format so data from mixed equipment can be combined. The processor pairs simultaneously observing receivers and computes each <strong>baseline vector</strong> &mdash; resolving the carrier-phase integer ambiguities and outputting &Delta;X, &Delta;Y, &Delta;Z with a covariance matrix describing its precision. Those baselines, with their covariances, become the observations for a <strong>least-squares network adjustment</strong> that yields final coordinates and rigorous error estimates. Understanding this chain lets the surveyor judge whether a result is trustworthy rather than merely accepting whatever number the software prints.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000001', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'text', '{"html":"<h3>Differencing and Precise Orbits</h3><p>Baseline processing relies on <strong>differencing</strong> the carrier-phase observations. <strong>Single differences</strong> (between two receivers to one satellite) cancel the satellite clock; <strong>double differences</strong> (between two receivers and two satellites) also cancel the receiver clocks and leave the integer ambiguities as clean unknowns; <strong>triple differences</strong> (across epochs) help detect cycle slips. For the best absolute accuracy, processors replace the broadcast orbit with <strong>precise ephemerides</strong> (e.g., IGS final orbits, available after a short delay) and apply precise clock products. The same precise products power <strong>Precise Point Positioning (PPP)</strong>, which obtains centimeter-to-decimeter absolute coordinates from a <em>single</em> receiver &mdash; no base &mdash; given a long enough observation, a useful option in remote areas.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000002', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'equation', '{"latex":"\\nabla\\Delta\\Phi = \\Phi_{1}^{j} - \\Phi_{1}^{k} - \\Phi_{2}^{j} + \\Phi_{2}^{k}","label":"Double difference (receivers 1,2 and satellites j,k) — cancels receiver and satellite clocks","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000003', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'text', '{"html":"<h3>The Network Adjustment and Its Statistics</h3><p>With baselines computed, the surveyor runs a <strong>least-squares adjustment</strong> in two stages. A <strong>minimally constrained</strong> adjustment holds just one station fixed; because the network is otherwise free, the residuals and <strong>loop closures</strong> reveal the <em>internal</em> quality of the observations &mdash; this is where you hunt blunders and bad baselines before tying to anything. Once the data are clean, a <strong>fully constrained</strong> adjustment holds all known datum control fixed, distributing any remaining inconsistency and yielding final coordinates referenced to the official datum. The output includes residuals, a variance factor (ideally near 1), standard deviations, and <strong>error ellipses</strong> that visualize each station''s positional uncertainty. Large or lopsided residuals point to a problem in the data or the control.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000004', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'table', '{"headers":["Stage","What is held fixed","What it tells you"],"rows":[["Baseline processing","—","ΔX,ΔY,ΔZ vectors + covariances per baseline"],["Minimally constrained","One station only","Internal consistency; finds blunders/bad baselines"],["Fully constrained","All known datum control","Final datum coordinates + error ellipses"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000005', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'callout', '{"type":"info","text":"Sequence matters: always pass the minimally constrained adjustment (clean residuals and loop closures) BEFORE adding datum constraints. Constraining to control too early can mask observation blunders by absorbing them into the network, producing pretty coordinates that are quietly wrong."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000006', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A least-squares network adjustment outputs adjusted coordinates with error ellipses showing each station''s positional uncertainty."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0007-0000-0000-000000000007', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'key_takeaways', '{"title":"Key Takeaways","items":["Post-processing flows from RINEX raw data → baseline vectors with covariances → least-squares network adjustment → coordinates with statistics.","Double differencing cancels satellite and receiver clocks, leaving ambiguities; triple differences flag cycle slips.","Precise ephemerides and PPP improve absolute accuracy; PPP yields coordinates from a single receiver without a base.","Run a minimally constrained adjustment first to test internal consistency and find blunders, then a fully constrained one to tie to datum control.","Interpret residuals, loop closures, variance factor, and error ellipses to judge whether the result is trustworthy."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000000', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'text', '{"html":"<h3>The Error Budget</h3><p>A GNSS position is only as good as the ranges that feed it, and every range carries error from several sources. The combined effect of all per-satellite range errors is summarized as the <strong>User Equivalent Range Error (UERE)</strong>. The biggest contributors are atmospheric: the <strong>ionosphere</strong> (a dispersive, charged layer ~50&ndash;1000 km up) and the <strong>troposphere</strong> (the lower, wet atmosphere). To these add <strong>multipath</strong> (signals reflecting off nearby surfaces), residual <strong>satellite orbit and clock</strong> errors, and <strong>receiver/antenna</strong> effects such as antenna phase-center variation. Understanding which errors cancel by differencing and which do not is the key to choosing the right method for a given accuracy.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000001', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'table', '{"headers":["Error source","Nature","Mitigation"],"rows":[["Ionospheric delay","Frequency-dependent (dispersive)","Dual-frequency combination; broadcast model (single-freq)"],["Tropospheric delay","Not frequency-dependent; weather-driven","Tropospheric models; estimate in adjustment; short baselines"],["Multipath","Reflections off ground/structures","Good site, choke-ring/calibrated antenna, longer occupation"],["Orbit (ephemeris) error","Imperfect broadcast orbit","Differencing; precise (IGS) ephemerides"],["Satellite clock error","Atomic clock drift/model error","Differencing; precise clock products"],["Receiver/antenna","Noise, phase-center variation","Calibrated antennas, consistent antenna models/heights"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000002', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'text', '{"html":"<h3>Atmosphere and Multipath</h3><p>The <strong>ionospheric delay</strong> depends on signal frequency, so it is largely removed by combining two frequencies &mdash; the chief reason survey receivers are dual-frequency. The <strong>tropospheric delay</strong> is <em>not</em> frequency-dependent and so cannot be cancelled that way; instead it is reduced by atmospheric models (functions of elevation angle, pressure, temperature, humidity) and by keeping baselines short so the delay is nearly common to both receivers and differences away. <strong>Multipath</strong> &mdash; the signal arriving via reflection from a building, vehicle, water, or the ground &mdash; is insidious because it varies with the site and does not difference out. It is fought in the field: choose open sites, avoid reflective surfaces, raise the elevation mask, use a quality (e.g., choke-ring) antenna, and occupy longer so the geometry changes and the multipath averages down.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000003', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'text', '{"html":"<h3>DOP: Geometry Is Everything</h3><p>Even perfect ranges give a poor position if the satellites are badly placed. <strong>Dilution of Precision (DOP)</strong> is the dimensionless factor that maps range error into position error, derived purely from the <em>geometry</em> of the visible satellites. Satellites spread evenly across the sky give a strong (low) DOP; satellites clustered together give a weak (high) DOP and large position error. Variants describe different components: <strong>PDOP</strong> (3-D position), <strong>HDOP</strong> (horizontal), <strong>VDOP</strong> (vertical), <strong>GDOP</strong> (geometry including time). A practical estimate is that the position error roughly equals the <strong>UERE multiplied by DOP</strong>. Crews monitor PDOP and avoid observing when it spikes (e.g., briefly when too few satellites are well distributed).</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000004', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'equation', '{"latex":"\\sigma_{\\text{position}} \\approx \\text{UERE} \\times \\text{PDOP}","label":"Estimated position error = User Equivalent Range Error × Dilution of Precision","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000005', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'callout', '{"type":"info","text":"Field rule of thumb: plan observations for low PDOP and good sky visibility, and keep a sensible elevation mask (often ~10–15°) to reject low, multipath- and atmosphere-prone signals. Mission-planning software predicts satellite geometry and PDOP for any site and time."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000006', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Geometry and DOP. Well-distributed satellites yield low DOP and small error; clustered satellites yield high DOP and large error even with identical range precision."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0008-0000-0000-000000000007', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'key_takeaways', '{"title":"Key Takeaways","items":["Major range errors: ionospheric delay (dual-frequency removable), tropospheric delay (modeled), multipath (sited away), and orbit/clock errors (differenced, precise products).","The ionosphere is frequency-dependent and cancels with two frequencies; the troposphere is not and must be modeled.","Multipath does not difference out — fight it with good sites, quality antennas, elevation masks, and longer occupations.","DOP turns satellite geometry into a position-error multiplier; low DOP is good, high DOP is bad.","Estimated position error ≈ UERE × DOP, so both clean ranges and good geometry are required."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000000', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'text', '{"html":"<h3>Heights: Ellipsoid vs. Geoid</h3><p>The most common pitfall in integrating GNSS with conventional work is <strong>height</strong>. GNSS directly gives the <strong>ellipsoidal height (h)</strong> &mdash; the distance above the smooth mathematical ellipsoid. But levels, benchmarks, and engineering plans use the <strong>orthometric height (H)</strong> &mdash; elevation above the <strong>geoid</strong>, the equipotential surface approximating mean sea level, which is what water &lsquo;runs downhill&rsquo; relative to. The two differ by the <strong>geoid height (N)</strong>, the separation between ellipsoid and geoid at that point. The relationship is simple and must be applied: <strong>H = h &minus; N</strong>. The geoid height N comes from a published geoid model (in the U.S., NGS GEOID models such as GEOID18). Skipping this conversion produces elevations off by tens of meters &mdash; the value of N in the conterminous U.S. ranges roughly from about &minus;8 m to &minus;53 m.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000001', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'equation', '{"latex":"H = h - N","label":"Orthometric height = ellipsoidal height − geoid height","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000002', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'text', '{"html":"<h3>Datum Considerations</h3><p>GNSS satellites broadcast in a global, Earth-centered frame &mdash; <strong>WGS84</strong> for GPS, aligned closely with the international <strong>ITRF</strong>. U.S. surveying control, however, is published on <strong>NAD83</strong>, which is fixed to the stable North American plate. WGS84/ITRF and NAD83 differ by roughly <strong>1&ndash;2 meters</strong> and, because the plate moves, the difference changes slowly with time. A surveyor must always know which datum (and which realization/epoch) a coordinate is in: feeding raw WGS84 GNSS results into a NAD83 project, or mixing realizations, introduces systematic errors of a meter or more. RTNs and OPUS deliver coordinates explicitly in NAD83 (or ITRF) so the surveyor can keep them consistent.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000003', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'callout', '{"type":"warning","text":"Coming change: NGS plans to replace NAD83 and NAVD88 with modernized reference frames — the North American Terrestrial Reference Frame of 2022 (NATRF2022) for horizontal and a new geopotential (geoid-based) vertical datum. These will be time-dependent and better tied to ITRF/the geoid, changing published coordinates and elevations. Surveyors must track the rollout and state which datum/epoch every deliverable uses."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000004', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'text', '{"html":"<h3>Combining GNSS with the Total Station</h3><p>GNSS and conventional instruments are complementary, not competing. <strong>GNSS</strong> excels at establishing widely spaced control quickly, with no need for intervisibility, and at long ties &mdash; but it fails under heavy canopy, indoors, in tunnels, and against tall structures, and its vertical component is weakest. The <strong>total station</strong> gives high relative accuracy over short distances, strong vertical angles, and works where the sky is blocked &mdash; but it needs line of sight and accumulates error over long traverses. The standard integrated workflow uses GNSS to set several control monuments around a project, then runs total-station traverses and detail from that GNSS control, checking back into it. For construction, the GNSS-derived control is tied to the project''s coordinate system by a <strong>site localization (calibration)</strong> &mdash; a best-fit transformation onto known site points &mdash; so RTK and total-station measurements share one consistent grid.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000005', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'table', '{"headers":["Capability","GNSS","Total station"],"rows":[["Needs sky view","Yes (fails under canopy/indoors)","No"],["Needs line of sight","No","Yes"],["Best at","Control, long ties, fast coverage","Detail, short high-accuracy, strong vertical"],["Vertical strength","Weaker (needs geoid model)","Strong"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000006', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'accordion', '{"sections":[{"title":"Worked idea: GNSS height to elevation","content":"<p>A GNSS observation gives an ellipsoidal height h = 152.40 m at a point where the geoid model returns a geoid height N = &minus;25.60 m. The orthometric elevation is H = h &minus; N = 152.40 &minus; (&minus;25.60) = <strong>178.00 m</strong>. Note that because N is negative here, subtracting it <em>adds</em> to the elevation &mdash; a common sign-error trap.</p>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000007', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Ellipsoid, geoid, and ground point. Ellipsoidal height h, geoid height N, and orthometric height H are related by H = h − N."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1110-0009-0000-0000-000000000008', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'key_takeaways', '{"title":"Key Takeaways","items":["GNSS gives ellipsoidal height h; convert to orthometric elevation with a geoid model: H = h − N (watch the sign of N).","WGS84/ITRF (GNSS broadcast) and NAD83 (U.S. control) differ by ~1–2 m and change with time — always know your datum and epoch.","The modernized NATRF2022 and a new geoid-based vertical datum will replace NAD83/NAVD88; track the rollout and label deliverables.","GNSS sets control fast without intervisibility; total stations supply detail and work where the sky is blocked.","Integrate via shared GNSS control and a site localization (calibration) so GNSS and total-station data share one grid."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000001', 'GNSS vs. GPS', 'GNSS (Global Navigation Satellite System) is the generic term for any satellite positioning constellation; GPS is the specific U.S. system. A modern receiver that tracks multiple constellations is a GNSS receiver.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000002', 'Pseudorange', 'The raw satellite-to-receiver distance from signal travel time, contaminated by the receiver clock bias (and other errors). The clock bias is solved as a fourth unknown, which is why four satellites are required.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000003', 'GNSS segments', 'Space segment (the satellites), control segment (ground tracking/upload stations that maintain orbits and clocks), and user segment (receivers).', 'Think satellites, ground masters, and your rover.', 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000004', 'Galileo and BeiDou', 'The European Union''s (Galileo) and China''s (BeiDou/BDS) global navigation satellite systems. Together with GPS and GLONASS they form the four global GNSS constellations tracked by modern survey receivers.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e702897d-97dc-46bb-b473-c364fb27a420', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000005', 'Medium Earth Orbit (MEO)', 'The orbital band (~19,000–23,000 km altitude) where GNSS navigation satellites fly, with orbital periods near 12 hours and inclined planes that spread satellites across the sky.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e702897d-97dc-46bb-b473-c364fb27a420', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000006', 'Multi-constellation advantage', 'Tracking GPS + GLONASS + Galileo + BeiDou puts many more satellites in view, improving geometry (DOP) and giving reliable fixes in obstructed environments where a single constellation would fail.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e702897d-97dc-46bb-b473-c364fb27a420', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000007', 'L1 / L2 / L5', 'The GPS carrier frequencies: L1 = 1575.42 MHz, L2 = 1227.60 MHz, L5 = 1176.45 MHz. Survey receivers use two or more to remove ionospheric delay and resolve ambiguities.', NULL, 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000008', 'C/A code vs. P(Y) code', 'C/A (Coarse/Acquisition) is the civil code on L1, easy to acquire and meter-level. P(Y) is the encrypted Precise code on L1 and L2 with a higher chipping rate for finer code ranging.', NULL, 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000009', 'Integer ambiguity', 'The unknown whole number of carrier-wavelength cycles between satellite and antenna in a carrier-phase measurement. Resolving it (''fixing'') converts a float solution into a centimeter-level fixed solution.', NULL, 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000010', 'Carrier phase vs. code phase', 'Code-phase (pseudorange) measurement is robust and instantaneous but meter-level; carrier-phase measurement gives millimeter resolution but requires resolving the integer ambiguity.', NULL, 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000011', 'Relative (differential) positioning', 'Determining the vector between two simultaneously observing receivers. Because both see nearly the same satellite, orbit, and atmospheric errors, differencing cancels them, yielding a precise baseline.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000012', 'Baseline vector', 'The three-dimensional difference (ΔX, ΔY, ΔZ) between two antennas computed from simultaneous carrier-phase observations. Static networks are built from many independent baselines.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000013', 'Static vs. fast-static', 'Static uses long occupations (20 min to hours) and works on long baselines and geodetic control; fast-static uses a few minutes on short baselines with strong geometry and dual-frequency data. Both are post-processed.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000014', 'RTK (Real-Time Kinematic)', 'A GNSS method giving centimeter positions in real time: a base over a known point broadcasts corrections to a rover, which resolves carrier-phase ambiguities on the fly. Used for topo, stakeout, and layout.', NULL, 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000015', 'Fixed vs. float solution', 'A ''fixed'' solution has the integer ambiguities resolved and is centimeter-accurate (survey-grade); a ''float'' solution is unresolved and only decimeter-level. Only fixed solutions should be stored as survey points.', NULL, 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000016', 'PPK (Post-Processed Kinematic)', 'Kinematic surveying where base and rover log raw data and the baselines are computed later in the office, eliminating the real-time data link and allowing more robust ambiguity resolution.', NULL, 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000017', 'Real-Time Network (RTN) / Network RTK', 'A permanent grid of GNSS reference stations whose server models regional errors and streams corrections to rovers over the internet, providing centimeter RTK without a user-operated base.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000018', 'Virtual Reference Station (VRS)', 'A network-RTK method in which the server synthesizes the observations of an imaginary base near the rover''s position, so the rover works as though a real base were only meters away.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000019', 'CORS', 'Continuously Operating Reference Stations — permanent GNSS stations (coordinated by NGS in the U.S.) whose freely archived data tie to the National Spatial Reference System, supporting OPUS post-processing and real-time networks.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000020', 'OPUS', 'The NGS Online Positioning User Service: upload a static GNSS data file and it returns NSRS coordinates by processing against nearby CORS — a free way to establish or check a control point.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000021', 'RINEX', 'Receiver Independent Exchange format — a standard text format for raw GNSS observation and navigation data, letting data from different receiver brands be combined and post-processed together.', NULL, 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000022', 'Double differencing', 'Differencing carrier-phase observations between two receivers and two satellites. It cancels both satellite and receiver clock errors, leaving the integer ambiguities as the key unknowns to resolve.', NULL, 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000023', 'Minimally vs. fully constrained adjustment', 'A minimally constrained adjustment fixes only one station to test the network''s internal consistency and find blunders; a fully constrained adjustment fixes all known datum control to produce final datum coordinates.', NULL, 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000024', 'Precise Point Positioning (PPP)', 'Absolute positioning of a single receiver (no base) using precise satellite orbit and clock products, achieving centimeter-to-decimeter accuracy with sufficient observation time. Useful in remote areas.', NULL, 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000025', 'Ionospheric vs. tropospheric delay', 'Ionospheric delay is frequency-dependent (dispersive) and is removed by dual-frequency observation; tropospheric delay is not frequency-dependent and must be reduced by atmospheric models and short baselines.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000026', 'Multipath', 'Range error from a satellite signal arriving via reflection off nearby surfaces. It does not difference out and is mitigated by good site selection, quality antennas, elevation masks, and longer occupations.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000027', 'Dilution of Precision (DOP)', 'A dimensionless factor from satellite geometry that multiplies range error into position error. Low DOP (well-spread satellites) is good; high DOP (clustered satellites) is poor. Variants: PDOP, HDOP, VDOP, GDOP.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000028', 'UERE', 'User Equivalent Range Error — the combined per-satellite range error from all sources. Estimated position error ≈ UERE × DOP.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000029', 'Ellipsoidal vs. orthometric height', 'Ellipsoidal height (h) is measured from the reference ellipsoid (what GNSS gives); orthometric height (H) is elevation above the geoid (what levels/benchmarks use). They are related by H = h − N.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000030', 'Geoid height (N)', 'The separation between the ellipsoid and the geoid at a point, taken from a geoid model (e.g., NGS GEOID18). Used to convert GNSS ellipsoidal height to orthometric elevation: H = h − N.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000031', 'NAD83 vs. WGS84/ITRF', 'NAD83 is the U.S. control datum fixed to the North American plate; WGS84/ITRF is the global frame GPS broadcasts in. They differ by ~1–2 m and the difference changes with time, so datum/epoch must be tracked.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000032', 'NATRF2022', 'The North American Terrestrial Reference Frame of 2022 — NGS''s planned modernized, time-dependent horizontal datum (with a new geoid-based vertical datum) that will replace NAD83 and NAVD88.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1140-0000-0000-0000-000000000033', 'Site localization (calibration)', 'A best-fit transformation tying GNSS coordinates to a project''s local control points so GNSS (RTK) and total-station measurements share one consistent site grid.', NULL, 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', 'surveying', ARRAY['buildout','module-11']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000001', 'Why does an autonomous GNSS position require a minimum of four satellites rather than three?', 'multiple_choice', '["Three satellites cannot reach the receiver simultaneously","A fourth satellite is needed to solve for the receiver clock bias in addition to the three position coordinates","The fourth satellite measures velocity","Three satellites give a 2-D position only by law"]'::jsonb, 'A fourth satellite is needed to solve for the receiver clock bias in addition to the three position coordinates', 'The receiver clock is not synchronized to satellite time, so its bias is a fourth unknown alongside X, Y, Z. Four pseudoranges solve four unknowns. Three would leave the clock error unresolved.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000002', 'The ground stations that track satellites, compute precise orbits and clock corrections, and upload them to the satellites make up which GNSS segment?', 'multiple_choice', '["Space segment","Control segment","User segment","Datum segment"]'::jsonb, 'Control segment', 'The control segment monitors the satellites and uploads orbit/clock corrections. The space segment is the satellites themselves; the user segment is the receivers.', 'easy', 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000003', 'GPS and GNSS are exact synonyms; the terms can always be used interchangeably.', 'true_false', '["True","False"]'::jsonb, 'False', 'GNSS is the generic term for any navigation satellite constellation; GPS is the specific U.S. system and only one GNSS among GLONASS, Galileo, and BeiDou.', 'easy', 'c100000b-0000-0000-0000-00000000000b', 'dc0422fa-cbeb-434c-aee0-2e0e8914bcad', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000004', 'Which set correctly lists the four global GNSS constellations and their operators?', 'multiple_choice', '["GPS (USA), GLONASS (Russia), Galileo (EU), BeiDou (China)","GPS (USA), QZSS (Japan), NavIC (India), Galileo (EU)","GPS (USA), GLONASS (China), Galileo (Russia), BeiDou (EU)","GPS (USA), WAAS (USA), EGNOS (EU), GLONASS (Russia)"]'::jsonb, 'GPS (USA), GLONASS (Russia), Galileo (EU), BeiDou (China)', 'The four global constellations are GPS (USA), GLONASS (Russia), Galileo (EU), and BeiDou (China). QZSS and NavIC are regional; WAAS/EGNOS are augmentation systems, not standalone GNSS.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'e702897d-97dc-46bb-b473-c364fb27a420', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000005', 'What is the chief surveying benefit of a receiver that tracks multiple constellations rather than GPS alone?', 'multiple_choice', '["It eliminates the need for a geoid model","Many more satellites in view, improving geometry (DOP) and reliability in obstructed environments","It removes the integer ambiguity entirely","It works without any sky visibility"]'::jsonb, 'Many more satellites in view, improving geometry (DOP) and reliability in obstructed environments', 'Multi-constellation tracking greatly increases the number of satellites available, improving DOP and giving reliable fixes under canopy and in urban canyons where a single constellation might drop below four.', 'easy', 'c100000b-0000-0000-0000-00000000000b', 'e702897d-97dc-46bb-b473-c364fb27a420', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000006', 'Which statement correctly contrasts code-phase and carrier-phase measurements?', 'multiple_choice', '["Code-phase is millimeter-accurate; carrier-phase is meter-level","Code-phase (pseudorange) is robust but meter-level; carrier-phase is millimeter-resolution but carries an unknown integer ambiguity","Both are meter-level and identical in practice","Carrier-phase requires no satellites"]'::jsonb, 'Code-phase (pseudorange) is robust but meter-level; carrier-phase is millimeter-resolution but carries an unknown integer ambiguity', 'Code-phase ranging is instantaneous and robust but limited by the long code chips to meter level. Carrier-phase resolves to a fraction of a ~19 cm wavelength but must resolve the unknown integer number of whole cycles.', 'medium', 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000007', 'The primary reason survey-grade receivers observe two frequencies (e.g., L1 and L2) is to:', 'multiple_choice', '["Double the number of visible satellites","Cancel most of the frequency-dependent ionospheric delay and help fix ambiguities","Remove multipath completely","Eliminate the need for a base station"]'::jsonb, 'Cancel most of the frequency-dependent ionospheric delay and help fix ambiguities', 'Because ionospheric delay depends on frequency, combining two frequencies removes most of it — the largest error over long baselines — and also speeds integer ambiguity resolution.', 'medium', 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000008', 'The L1 GPS carrier frequency is 1575.42 MHz.', 'true_false', '["True","False"]'::jsonb, 'True', 'L1 = 1575.42 MHz, L2 = 1227.60 MHz, and L5 = 1176.45 MHz are the GPS carrier frequencies.', 'easy', 'c100000b-0000-0000-0000-00000000000b', '3e13d01b-282e-419d-8204-e75e67537775', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000009', 'Static GPS surveying achieves high accuracy primarily because:', 'multiple_choice', '["A single receiver measures absolute position very precisely","Simultaneous observation by two receivers lets differencing cancel common satellite, orbit, and atmospheric errors","It uses only the C/A code","It avoids carrier-phase measurements"]'::jsonb, 'Simultaneous observation by two receivers lets differencing cancel common satellite, orbit, and atmospheric errors', 'Static work is relative positioning: two receivers see nearly identical errors, which difference away, leaving a precise baseline vector. Carrier phase is central, not avoided.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000010', 'Compared with classic static, fast-static (rapid-static) is best characterized as:', 'multiple_choice', '["Longer occupations for very long baselines","Shorter occupations suited to short baselines with strong geometry and dual-frequency data","A real-time method needing a radio link","A single-frequency, navigation-grade technique"]'::jsonb, 'Shorter occupations suited to short baselines with strong geometry and dual-frequency data', 'Fast-static shortens occupation to a few minutes by exploiting dual-frequency data and good geometry, suiting dense short-baseline control. Both static and fast-static are post-processed, not real-time.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'dfc1c937-bd48-4033-8cb1-004ac5872e5e', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000011', 'In RTK, which solution state should be used to store survey-grade points?', 'multiple_choice', '["A float solution","A verified fixed solution (integer ambiguities resolved)","Any solution with 4+ satellites","An autonomous solution"]'::jsonb, 'A verified fixed solution (integer ambiguities resolved)', 'Only a fixed solution, in which the integer ambiguities are resolved, is centimeter-accurate. A float solution is only decimeter-level and must not be stored as a survey point.', 'easy', 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000012', 'The key difference between RTK and PPK is that:', 'multiple_choice', '["PPK gives results in real time; RTK is post-processed","RTK computes positions in real time via a data link; PPK logs raw data and resolves baselines in the office afterward","PPK does not use carrier phase","RTK requires no base station"]'::jsonb, 'RTK computes positions in real time via a data link; PPK logs raw data and resolves baselines in the office afterward', 'RTK needs a base-to-rover data link and gives positions instantly; PPK skips the link, logging data for office processing, which is more robust where a link is impractical.', 'medium', 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000013', 'An RTK rover passes under a tree and loses lock. What must happen before reliable points can be measured again?', 'short_answer', '[]'::jsonb, 'The rover drops to a float solution and must re-initialize (re-fix the integer ambiguities) to a verified fixed solution before storing points.', 'Loss of lock reverts the solution to float; the receiver must resolve the integer ambiguities again to return to a centimeter-level fixed solution.', 'medium', 'c100000b-0000-0000-0000-00000000000b', '28e3e9ec-70e5-43ba-bf60-0e554e32e613', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000014', 'In a Virtual Reference Station (VRS) network, the central server:', 'multiple_choice', '["Requires the user to set up a physical base over known control","Synthesizes the observations of an imaginary base near the rover''s position","Only works for post-processing, never real time","Eliminates the need for any reference stations"]'::jsonb, 'Synthesizes the observations of an imaginary base near the rover''s position', 'VRS uses the rover''s approximate location to generate the data a nearby virtual base would record, so the rover behaves as if a base were only meters away — no user base needed.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000015', 'What is CORS, and what role does it play in U.S. GNSS surveying?', 'short_answer', '[]'::jsonb, 'Continuously Operating Reference Stations — permanent GNSS stations (coordinated by NGS) whose freely archived data are tied to the National Spatial Reference System, supporting post-processing (e.g., OPUS) and real-time networks.', 'CORS provide datum-tied reference data that underpin both OPUS post-processing and many real-time networks, anchoring user results to the official NSRS datum.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'e0b5a381-0a8a-4663-9c8b-0816e62c44f9', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000016', 'Which adjustment should be run FIRST to detect blunders and bad baselines before tying a GNSS network to published control?', 'multiple_choice', '["A fully constrained adjustment holding all known control fixed","A minimally constrained adjustment holding only one station fixed","No adjustment is needed","A two-dimensional-only adjustment"]'::jsonb, 'A minimally constrained adjustment holding only one station fixed', 'A minimally constrained adjustment tests internal consistency (residuals, loop closures) without datum bias, revealing blunders. Constraining to control too early can mask observation errors.', 'hard', 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000017', 'Double differencing of carrier-phase observations is used because it:', 'multiple_choice', '["Doubles the measurement accuracy automatically","Cancels both satellite and receiver clock errors, leaving the integer ambiguities as the key unknowns","Removes multipath entirely","Eliminates the need for precise ephemerides"]'::jsonb, 'Cancels both satellite and receiver clock errors, leaving the integer ambiguities as the key unknowns', 'Single differences cancel the satellite clock; double differences (two receivers, two satellites) also cancel receiver clocks, isolating the integer ambiguities for resolution.', 'hard', 'c100000b-0000-0000-0000-00000000000b', '46586422-2833-4eb7-a4f0-f43afa0daae8', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000018', 'Which error source is frequency-dependent and therefore removable by combining two GNSS frequencies?', 'multiple_choice', '["Tropospheric delay","Ionospheric delay","Multipath","Antenna phase-center variation"]'::jsonb, 'Ionospheric delay', 'The ionosphere is dispersive (frequency-dependent), so a dual-frequency combination removes most of it. Tropospheric delay is not frequency-dependent, and multipath/antenna effects do not difference out this way.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000019', 'A high PDOP value indicates:', 'multiple_choice', '["Excellent satellite geometry and small position error","Poor satellite geometry that amplifies range error into larger position error","That the receiver clock is broken","That ionospheric delay has been removed"]'::jsonb, 'Poor satellite geometry that amplifies range error into larger position error', 'DOP scales range error into position error from the satellite geometry. High PDOP (clustered satellites) means weak geometry and large position error; low PDOP is desirable.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000020', 'Multipath error can be reliably removed simply by observing two frequencies, just like the ionosphere.', 'true_false', '["True","False"]'::jsonb, 'False', 'Multipath is site-specific and does not difference out or cancel with dual frequency. It is mitigated by good site selection, quality antennas, elevation masks, and longer occupations.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'fbe7132a-2992-4500-b21e-33f4f5dc5d69', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000021', 'GNSS gives an ellipsoidal height h = 210.00 m at a point where the geoid height is N = −24.00 m. What is the orthometric elevation H (m)?', 'numeric_input', '[]'::jsonb, '234', 'H = h − N = 210.00 − (−24.00) = 234.00 m. Because N is negative, subtracting it adds to the elevation — a common sign trap.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000022', 'Regarding datums, which statement is correct for U.S. surveying?', 'multiple_choice', '["WGS84/ITRF and NAD83 are identical, so no conversion is ever needed","WGS84/ITRF and NAD83 differ by roughly 1–2 m, so the surveyor must track which datum and epoch coordinates are in","GNSS always outputs NAD83 directly with no datum concern","NAD83 is a global frame fixed to no plate"]'::jsonb, 'WGS84/ITRF and NAD83 differ by roughly 1–2 m, so the surveyor must track which datum and epoch coordinates are in', 'NAD83 is fixed to the North American plate; WGS84/ITRF is a global frame. They differ by ~1–2 m and the difference changes with time, so datum/epoch must be tracked to avoid systematic error.', 'hard', 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1130-0000-0000-0000-000000000023', 'When integrating GNSS with total-station work on a project, GNSS is typically used to ______ while the total station provides ______.', 'multiple_choice', '["set detail points; widely spaced control","establish widely spaced control quickly; detail and measurements where the sky is blocked","measure indoors; measure under canopy","replace all conventional measurements; nothing"]'::jsonb, 'establish widely spaced control quickly; detail and measurements where the sky is blocked', 'GNSS sets control fast without intervisibility but fails under obstruction; the total station supplies detail and works where the sky is blocked. They are integrated through shared control and a site localization.', 'medium', 'c100000b-0000-0000-0000-00000000000b', 'db07fb79-9728-47d7-8fc0-228e3e527bbf', ARRAY['buildout','module-11']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
