INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1160-0000-0000-0000-000000000001', 'A GNSS observation gives an ellipsoidal height of h = {{h:f2}} m at a point where the geoid model returns a geoid height of N = {{N:f2}} m. Using H = h − N, what is the orthometric (elevation) height H in meters?', 'numeric_input', '[]'::jsonb, '0', 'Orthometric height H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} m. Because N is negative, subtracting it adds to the elevation — a common sign trap.', 'easy', 'c100000b-0000-0000-0000-00000000000b', NULL, ARRAY['buildout','module-11','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1150-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1160-0000-0000-0000-000000000002', 'The combined per-satellite User Equivalent Range Error (UERE) for an observation is {{uere:f1}} m and the satellite geometry gives a PDOP of {{pdop:f1}}. Estimate the 3-D position error (m) using σ ≈ UERE × PDOP.', 'numeric_input', '[]'::jsonb, '0', 'Estimated position error ≈ UERE × PDOP = {{uere:f1}} × {{pdop:f1}} = {{_answer}} m. A high PDOP (weak geometry) inflates the position error even when the ranges themselves are good.', 'medium', 'c100000b-0000-0000-0000-00000000000b', NULL, ARRAY['buildout','module-11','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1150-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1160-0000-0000-0000-000000000003', 'A GNSS baseline accuracy is specified as a constant term of {{a}} mm plus {{b}} ppm of the baseline length. For a baseline of {{D:f1}} km, what is the expected baseline error in MILLIMETERS? (1 ppm = 1 mm per km.)', 'numeric_input', '[]'::jsonb, '0', 'Baseline error = a + b·D = {{a}} mm + {{b}} ppm × {{D:f1}} km = {{a}} + {{ppmTerm:f1}} = {{_answer}} mm. The constant term dominates on short baselines; the ppm term grows with length.', 'medium', 'c100000b-0000-0000-0000-00000000000b', NULL, ARRAY['buildout','module-11','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1150-0000-0000-0000-000000000003', 0.1);
